import{_ as e,o as a,c as s,ae as d}from"./chunks/framework.DTwQaIIa.js";const g=JSON.parse('{"title":"Triggers & Casting","description":"","frontmatter":{},"headers":[],"relativePath":"en/modules/skills/triggers.md","filePath":"en/modules/skills/triggers.md"}'),i={name:"en/modules/skills/triggers.md"};function n(r,t,o,l,c,p){return a(),s("div",null,[...t[0]||(t[0]=[d(`<h1 id="triggers-casting" tabindex="-1">Triggers &amp; Casting <a class="header-anchor" href="#triggers-casting" aria-label="Permalink to &quot;Triggers &amp; Casting&quot;">​</a></h1><h2 id="active-triggers" tabindex="-1">Active Triggers <a class="header-anchor" href="#active-triggers" aria-label="Permalink to &quot;Active Triggers&quot;">​</a></h2><p>EmakiSkills provides 14 built-in active triggers. Active triggers require the player to press keys in cast mode:</p><table tabindex="0"><thead><tr><th>Trigger ID</th><th>Display Name</th><th>Event Source</th><th>Conflict Rule</th></tr></thead><tbody><tr><td><code>left_click</code></td><td>[Left Click]</td><td><code>InteractTriggerSource</code></td><td>Conflicts with <code>shift_left_click</code></td></tr><tr><td><code>right_click</code></td><td>[Right Click]</td><td><code>InteractTriggerSource</code></td><td>Conflicts with <code>shift_right_click</code></td></tr><tr><td><code>shift_left_click</code></td><td>[Shift + Left Click]</td><td><code>InteractTriggerSource</code></td><td>Conflicts with <code>left_click</code></td></tr><tr><td><code>shift_right_click</code></td><td>[Shift + Right Click]</td><td><code>InteractTriggerSource</code></td><td>Conflicts with <code>right_click</code></td></tr><tr><td><code>drop_q</code></td><td>[Q Key]</td><td><code>DropTriggerSource</code></td><td>No conflicts</td></tr><tr><td><code>hotbar_1</code></td><td>[Number Key 1]</td><td><code>HotbarTriggerSource</code></td><td>No conflicts</td></tr><tr><td><code>hotbar_2</code></td><td>[Number Key 2]</td><td><code>HotbarTriggerSource</code></td><td>No conflicts</td></tr><tr><td><code>hotbar_3</code></td><td>[Number Key 3]</td><td><code>HotbarTriggerSource</code></td><td>No conflicts</td></tr><tr><td><code>hotbar_4</code></td><td>[Number Key 4]</td><td><code>HotbarTriggerSource</code></td><td>No conflicts</td></tr><tr><td><code>hotbar_5</code></td><td>[Number Key 5]</td><td><code>HotbarTriggerSource</code></td><td>No conflicts</td></tr><tr><td><code>hotbar_6</code></td><td>[Number Key 6]</td><td><code>HotbarTriggerSource</code></td><td>No conflicts</td></tr><tr><td><code>hotbar_7</code></td><td>[Number Key 7]</td><td><code>HotbarTriggerSource</code></td><td>No conflicts</td></tr><tr><td><code>hotbar_8</code></td><td>[Number Key 8]</td><td><code>HotbarTriggerSource</code></td><td>No conflicts</td></tr><tr><td><code>hotbar_9</code></td><td>[Number Key 9]</td><td><code>HotbarTriggerSource</code></td><td>No conflicts</td></tr></tbody></table><h3 id="conflict-rules" tabindex="-1">Conflict Rules <a class="header-anchor" href="#conflict-rules" aria-label="Permalink to &quot;Conflict Rules&quot;">​</a></h3><p>Conflict rules are configured via <code>incompatible_with</code>. When two triggers conflict with each other, the same player cannot bind them to different slots simultaneously.</p><p>Typical conflict: <code>left_click</code> ↔ <code>shift_left_click</code>, because the Shift+Left-click event in Bukkit also triggers the left-click event simultaneously, causing ambiguity.</p><h3 id="event-sources" tabindex="-1">Event Sources <a class="header-anchor" href="#event-sources" aria-label="Permalink to &quot;Event Sources&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Source Class</th><th>Listened Event</th><th>Description</th></tr></thead><tbody><tr><td><code>InteractTriggerSource</code></td><td><code>PlayerInteractEvent</code></td><td>Left/right click and Shift combinations</td></tr><tr><td><code>DropTriggerSource</code></td><td><code>PlayerDropItemEvent</code></td><td>Q key item drop</td></tr><tr><td><code>HotbarTriggerSource</code></td><td><code>PlayerItemHeldEvent</code></td><td>Number key hotbar switching</td></tr></tbody></table><hr><h2 id="passive-triggers" tabindex="-1">Passive Triggers <a class="header-anchor" href="#passive-triggers" aria-label="Permalink to &quot;Passive Triggers&quot;">​</a></h2><p>Passive triggers are automatically fired by game events without requiring cast mode. Passive skills declare which passive triggers they respond to via the <code>passive_triggers</code> list in their definition files.</p><p>EmakiSkills provides 22 built-in passive triggers:</p><table tabindex="0"><thead><tr><th>Trigger ID</th><th>Display Name</th><th>Trigger Event</th><th>Target Passing</th></tr></thead><tbody><tr><td><code>attack</code></td><td>[Attack Hit]</td><td>Player attacks entity</td><td>Attacked entity</td></tr><tr><td><code>damaged_by_entity</code></td><td>[Damaged by Entity]</td><td>Player damaged by entity</td><td>Attacker</td></tr><tr><td><code>damaged</code></td><td>[Damaged]</td><td>Any damage received</td><td>None</td></tr><tr><td><code>death</code></td><td>[Death]</td><td>Player death</td><td>None</td></tr><tr><td><code>kill_entity</code></td><td>[Kill Entity]</td><td>Kill non-player entity</td><td>Killed entity</td></tr><tr><td><code>kill_player</code></td><td>[Kill Player]</td><td>Kill player</td><td>Killed player</td></tr><tr><td><code>shoot_bow</code></td><td>[Shoot Bow]</td><td>Shoot bow</td><td>None</td></tr><tr><td><code>arrow_hit</code></td><td>[Arrow Hit Entity]</td><td>Arrow hits entity</td><td>Hit entity</td></tr><tr><td><code>arrow_land</code></td><td>[Arrow Land]</td><td>Arrow hits block</td><td>None (passes landing point)</td></tr><tr><td><code>shoot_trident</code></td><td>[Throw Trident]</td><td>Throw trident</td><td>None</td></tr><tr><td><code>trident_hit</code></td><td>[Trident Hit Entity]</td><td>Trident hits entity</td><td>Hit entity</td></tr><tr><td><code>trident_land</code></td><td>[Trident Land]</td><td>Trident hits block</td><td>None (passes landing point)</td></tr><tr><td><code>break_block</code></td><td>[Break Block]</td><td>Break block</td><td>None (passes block location)</td></tr><tr><td><code>place_block</code></td><td>[Place Block]</td><td>Place block</td><td>None (passes block location)</td></tr><tr><td><code>drop_item</code></td><td>[Drop Item]</td><td>Drop item (not sneaking)</td><td>Dropped item entity</td></tr><tr><td><code>shift_drop_item</code></td><td>[Shift+Drop Item]</td><td>Drop item (sneaking)</td><td>Dropped item entity</td></tr><tr><td><code>swap_items</code></td><td>[Swap Items]</td><td>Swap hand items (not sneaking)</td><td>None</td></tr><tr><td><code>shift_swap_items</code></td><td>[Shift+Swap Items]</td><td>Swap hand items (sneaking)</td><td>None</td></tr><tr><td><code>login</code></td><td>[Login]</td><td>Player joins server</td><td>None</td></tr><tr><td><code>sneak</code></td><td>[Sneak]</td><td>Start sneaking</td><td>None</td></tr><tr><td><code>teleport</code></td><td>[Teleport]</td><td>Player teleport</td><td>None (passes target location)</td></tr><tr><td><code>timer</code></td><td>[Timer]</td><td>Periodic check</td><td>None</td></tr></tbody></table><p>The <code>timer</code> trigger interval is configured via <code>passive_trigger_settings.timer_interval_ticks</code>, default 20 ticks (1 second).</p><h3 id="passive-casting-flow" tabindex="-1">Passive Casting Flow <a class="header-anchor" href="#passive-casting-flow" aria-label="Permalink to &quot;Passive Casting Flow&quot;">​</a></h3><p>The passive skill casting flow is simpler than active skills — it skips cast mode check and slot binding lookup:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Game event → PassiveTriggerDispatcher.dispatch(invocation)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─ 1. Check trigger exists and is enabled</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─ 2. Iterate all unlocked skills</span></span>
<span class="line"><span>    │     Filter: trigger_type == passive &amp;&amp; passive_triggers contains current trigger</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─ 3. Check forced delay / global cooldown / skill cooldown</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─ 4. Check resource costs</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─ 5. MythicMobs cast (passes event target info)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └─ Post-success: consume resources, record cooldowns</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Target Passing</p><p>When a passive skill triggers, the event&#39;s target entity and location are passed to MythicMobs <code>@target</code>. For example, the <code>attack</code> trigger passes the attacked entity as target. Triggers without a target entity use the player as caster without passing additional targets.</p></div><hr><h2 id="cast-mode-entry" tabindex="-1">Cast Mode Entry <a class="header-anchor" href="#cast-mode-entry" aria-label="Permalink to &quot;Cast Mode Entry&quot;">​</a></h2><p>Cast mode uses the F key (<code>PlayerSwapHandItemsEvent</code>) to toggle. The F key&#39;s original swap-hand function is intercepted by cast mode.</p><p>Active skills require the player to enter cast mode first. Outside cast mode, active trigger events are ignored. Passive skills are not affected by cast mode and are always listening.</p><hr><h2 id="active-skill-casting-flow" tabindex="-1">Active Skill Casting Flow <a class="header-anchor" href="#active-skill-casting-flow" aria-label="Permalink to &quot;Active Skill Casting Flow&quot;">​</a></h2><p>When an active trigger event reaches <code>CastAttemptService</code>, the following 10-step check is executed:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Trigger event → CastAttemptService.attemptCast(player, triggerId)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─ 1. Validate input</span></span>
<span class="line"><span>    │     player non-null, triggerId non-null</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─ 2. Check cast mode</span></span>
<span class="line"><span>    │     CastModeService.isCastModeEnabled(player) == true</span></span>
<span class="line"><span>    │     ✗ → Failure: NOT_IN_CAST_MODE</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─ 3. Find binding</span></span>
<span class="line"><span>    │     Iterate PlayerSkillProfile.bindings, find SkillSlotBinding matching triggerId</span></span>
<span class="line"><span>    │     ✗ → Failure: NO_BINDING</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─ 4. Find skill definition</span></span>
<span class="line"><span>    │     SkillRegistryService.getDefinition(binding.skillId)</span></span>
<span class="line"><span>    │     ✗ → Failure: SKILL_NOT_FOUND</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─ 5. Verify skill is still in unlock pool</span></span>
<span class="line"><span>    │     PlayerSkillStateService.getUnlockedSkills(player) contains binding.skillId</span></span>
<span class="line"><span>    │     ✗ → Failure: SOURCE_LOST (equipment unequipped)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─ 6. Check forced delay</span></span>
<span class="line"><span>    │     PlayerCastTimingState.isForcedDelayActive() == false</span></span>
<span class="line"><span>    │     ✗ → Failure: FORCED_DELAY_ACTIVE</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─ 7. Check global cooldown</span></span>
<span class="line"><span>    │     PlayerCastTimingState.isGlobalCooldownActive() == false</span></span>
<span class="line"><span>    │     ✗ → Failure: GLOBAL_COOLDOWN_ACTIVE</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─ 8. Check skill cooldown</span></span>
<span class="line"><span>    │     PlayerCastTimingState.isSkillOnCooldown(skillId) == false</span></span>
<span class="line"><span>    │     ✗ → Failure: SKILL_COOLDOWN_ACTIVE</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─ 9. Check resource costs</span></span>
<span class="line"><span>    │     Iterate SkillDefinition.resourceCosts:</span></span>
<span class="line"><span>    │     ├─ local-resource → Check PlayerLocalResourceState</span></span>
<span class="line"><span>    │     ├─ ea-resource → Check EA resource via EaBridge</span></span>
<span class="line"><span>    │     └─ ea-attribute-check → Check EA attribute via EaBridge</span></span>
<span class="line"><span>    │     ✗ → Failure: RESOURCE_INSUFFICIENT</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─ 10. MythicMobs cast</span></span>
<span class="line"><span>    │      MythicSkillCastService.cast(player, mythicSkillId)</span></span>
<span class="line"><span>    │      ✗ → Failure: MYTHIC_CAST_FAILED</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └─ Post-success handling:</span></span>
<span class="line"><span>         ├─ Consume resources (resources with operation = CONSUME)</span></span>
<span class="line"><span>         ├─ Record skill cooldown (cooldown_ticks)</span></span>
<span class="line"><span>         ├─ Record global cooldown (global_cooldown_ticks)</span></span>
<span class="line"><span>         └─ Record forced delay (forced_global_cast_delay_ticks)</span></span></code></pre></div><h3 id="failure-reason-enum" tabindex="-1">Failure Reason Enum <a class="header-anchor" href="#failure-reason-enum" aria-label="Permalink to &quot;Failure Reason Enum&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Failure Reason</th><th>Description</th></tr></thead><tbody><tr><td><code>NOT_IN_CAST_MODE</code></td><td>Not in cast mode</td></tr><tr><td><code>NO_BINDING</code></td><td>Trigger has no skill bound</td></tr><tr><td><code>SKILL_NOT_FOUND</code></td><td>Skill definition does not exist</td></tr><tr><td><code>SOURCE_LOST</code></td><td>Skill source lost (equipment unequipped)</td></tr><tr><td><code>FORCED_DELAY_ACTIVE</code></td><td>Forced delay active</td></tr><tr><td><code>GLOBAL_COOLDOWN_ACTIVE</code></td><td>Global cooldown active</td></tr><tr><td><code>SKILL_COOLDOWN_ACTIVE</code></td><td>Skill cooldown active</td></tr><tr><td><code>RESOURCE_INSUFFICIENT</code></td><td>Insufficient resources</td></tr><tr><td><code>MYTHIC_SKILL_NOT_FOUND</code></td><td>MythicMobs skill does not exist</td></tr><tr><td><code>MYTHIC_CAST_FAILED</code></td><td>MythicMobs cast failed</td></tr></tbody></table><hr><h2 id="actionbar-service" tabindex="-1">ActionBar Service <a class="header-anchor" href="#actionbar-service" aria-label="Permalink to &quot;ActionBar Service&quot;">​</a></h2><p><code>ActionBarService</code> periodically refreshes the player&#39;s ActionBar during cast mode, displaying the current skill slot status.</p><h3 id="template-variables" tabindex="-1">Template Variables <a class="header-anchor" href="#template-variables" aria-label="Permalink to &quot;Template Variables&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th></tr></thead><tbody><tr><td><code>{slot_1}</code> ~ <code>{slot_N}</code></td><td>Skill name for each slot (empty if unbound)</td></tr><tr><td><code>{slot_display}</code></td><td>Formatted display of all slots</td></tr><tr><td><code>{forced_delay}</code></td><td>Current forced delay remaining time</td></tr></tbody></table><h3 id="configuration-example" tabindex="-1">Configuration Example <a class="header-anchor" href="#configuration-example" aria-label="Permalink to &quot;Configuration Example&quot;">​</a></h3><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">actionbar</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  refresh_interval_ticks</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  template_cast_mode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&amp;aCast Mode &amp;7| {slot_display}&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  template_idle</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&amp;7Idle&quot;</span></span></code></pre></div><hr><h2 id="eabridge-mythicbridge" tabindex="-1">EaBridge &amp; MythicBridge <a class="header-anchor" href="#eabridge-mythicbridge" aria-label="Permalink to &quot;EaBridge &amp; MythicBridge&quot;">​</a></h2><h3 id="eabridge" tabindex="-1">EaBridge <a class="header-anchor" href="#eabridge" aria-label="Permalink to &quot;EaBridge&quot;">​</a></h3><p><code>EaBridge</code> obtains the <code>EmakiAttributeBridge</code> service via Bukkit&#39;s <code>ServicesManager</code>:</p><table tabindex="0"><thead><tr><th>Method</th><th>Description</th></tr></thead><tbody><tr><td><code>isAvailable()</code></td><td>Whether the EA bridge is available</td></tr><tr><td><code>readResourceCurrent()</code></td><td>Read the current value of an EA resource</td></tr><tr><td><code>consumeResource()</code></td><td>Consume an EA resource</td></tr><tr><td><code>readAttributeValue()</code></td><td>Read an EA attribute value</td></tr><tr><td><code>providerMode()</code></td><td>Current provider mode</td></tr></tbody></table><h3 id="mythicbridge" tabindex="-1">MythicBridge <a class="header-anchor" href="#mythicbridge" aria-label="Permalink to &quot;MythicBridge&quot;">​</a></h3><p><code>MythicBridge</code> wraps the MythicMobs API:</p><table tabindex="0"><thead><tr><th>Method</th><th>Description</th></tr></thead><tbody><tr><td><code>isAvailable()</code></td><td>Whether MythicMobs is available</td></tr><tr><td><code>skillExists()</code></td><td>Check if a MythicMobs skill exists</td></tr><tr><td><code>cast()</code></td><td>Execute a MythicMobs skill cast (active skills, no target)</td></tr><tr><td><code>cast(target, location)</code></td><td>Execute a MythicMobs skill cast (passive skills, passes target entity and location)</td></tr></tbody></table><hr><h2 id="gui-layout" tabindex="-1">GUI Layout <a class="header-anchor" href="#gui-layout" aria-label="Permalink to &quot;GUI Layout&quot;">​</a></h2><h3 id="skills-gui-—-skills-gui-6-rows" tabindex="-1">skills_gui — Skills GUI (6 rows) <a class="header-anchor" href="#skills-gui-—-skills-gui-6-rows" aria-label="Permalink to &quot;skills_gui — Skills GUI (6 rows)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Row 1: [Border] [Border] [Border] [Border] [Border] [Border] [Border] [Border] [Border]</span></span>
<span class="line"><span>Row 2: [Border] [Skill 1] [Skill 2] [Skill 3] [Skill 4] [Skill 5] [Skill 6] [Skill 7] [Border]</span></span>
<span class="line"><span>Row 3: [Border] [Skill 8] [Skill 9] [Skill 10] [...] [...] [...] [...] [Border]</span></span>
<span class="line"><span>Row 4: [Border] [Border] [Border] [Border] [Border] [Border] [Border] [Border] [Border]</span></span>
<span class="line"><span>Row 5: [Border] [Slot 1] [Slot 2] [Slot 3] [Border] [Cast Mode] [Border] [Border] [Border]</span></span>
<span class="line"><span>Row 6: [Border] [Border] [Border] [Border] [Border] [Border] [Border] [Border] [Border]</span></span></code></pre></div><ul><li>Skill area (rows 2-3): Displays all unlocked skills, click to select</li><li>Slot area (row 5): Displays currently bound skill slots</li><li>Cast mode button: Toggle cast mode on/off</li></ul><h3 id="trigger-select-gui-—-trigger-selection-gui-4-rows" tabindex="-1">trigger_select_gui — Trigger Selection GUI (4 rows) <a class="header-anchor" href="#trigger-select-gui-—-trigger-selection-gui-4-rows" aria-label="Permalink to &quot;trigger_select_gui — Trigger Selection GUI (4 rows)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Row 1: [Border] [Border] [Border] [Border] [Border] [Border] [Border] [Border] [Border]</span></span>
<span class="line"><span>Row 2: [Border] [Trigger 1] [Trigger 2] [Trigger 3] [Trigger 4] [Trigger 5] [Border] [Border] [Border]</span></span>
<span class="line"><span>Row 3: [Border] [Trigger 6] [Trigger 7] [...] [...] [...] [Border] [Border] [Border]</span></span>
<span class="line"><span>Row 4: [Border] [Border] [Border] [Border] [Back] [Border] [Border] [Border] [Border]</span></span></code></pre></div><ul><li>Trigger area (rows 2-3): Displays all available triggers; conflicting triggers are shown in gray</li><li>Back button (row 4): Return to the skills GUI</li></ul>`,52)])])}const u=e(i,[["render",n]]);export{g as __pageData,u as default};
